import { Injectable, inject, OnDestroy } from '@angular/core';
import { BaseService } from './Base/base.service';
import { Shift, RestaurantClosures } from '../models';
import { BehaviorSubject, Subscription } from 'rxjs';
import { AuthService } from './Base/auth.service';

@Injectable({
  providedIn: 'root'
})
export class ShiftService extends BaseService<Shift> implements OnDestroy {
  // Logica specifica per le chiusure (non gestita da BaseService)
  private closuresSubject = new BehaviorSubject<RestaurantClosures[]>([]);
  public closures$ = this.closuresSubject.asObservable();

  private authSubscription: Subscription;

  constructor() {
    super();
    // BaseService carica già i turni quando cambia ristorante (grazie a activeRestaurantId$)
    // Aggiungiamo il caricamento delle chiusure allo stesso trigger
    this.authSubscription = this.authService.activeRestaurantId$.subscribe(() => {
      this.loadClosures();
    });
  }

  // Implementazione obbligatoria per BaseService
  protected override getTableName(): string {
    return 'shifts';
  }

  // Sovrascriviamo loadData per gestire la creazione dei turni di default se non presenti
  override async loadData(additionalFilters?: Record<string, any>): Promise<void> {
    await super.loadData(additionalFilters); // carica i turni

    // Se non ci sono turni, crea quelli predefiniti
    if (this.data.length === 0) {
      const restaurantId = await this.getCurrentRestaurantId();
      if (restaurantId) {
        await this.createDefaultShifts(restaurantId);
        await super.loadData(additionalFilters); // ricarica dopo la creazione
      }
    }
  }

  /**
   * Crea i turni predefiniti (pranzo e cena) per un ristorante.
   */
  private async createDefaultShifts(restaurantId: string): Promise<void> {
    const defaultShifts = [
      {
        name: 'Pranzo',
        start_time: '12:00:00',
        end_time: '15:00:00',
        days_of_week: [1, 2, 3, 4, 5, 6, 7],
        is_active: true
      },
      {
        name: 'Cena',
        start_time: '19:00:00',
        end_time: '23:00:00',
        days_of_week: [1, 2, 3, 4, 5, 6, 7],
        is_active: true
      }
    ];

    try {
      // Usiamo il client Supabase direttamente (o potremmo usare super.create per ciascuno)
      const { error } = await this.supabaseService.getSupabaseClient()
        .from(this.getTableName())
        .insert(defaultShifts.map(s => ({ ...s, restaurant_id: restaurantId })));

      if (error) throw error;
      console.log('✅ Default shifts created');
    } catch (error) {
      console.error('❌ Error creating default shifts:', error);
    }
  }

  // --- Metodi specifici per i turni (non CRUD) ---

  /**
   * Restituisce il turno corrente in base all'orario (senza buffer).
   */
  getCurrentShift(): Shift | null {
    const now = new Date();
    const currentTime = now.toTimeString().split(' ')[0]; // HH:MM:SS
    const currentDay = now.getDay(); // 0=Domenica, 1=Lunedì, ... 6=Sabato
    const adjustedDay = currentDay === 0 ? 7 : currentDay;

    const activeShifts = this.data.filter(shift => shift.is_active);

    for (const shift of activeShifts) {
      if (shift.days_of_week.includes(adjustedDay)) {
        if (currentTime >= shift.start_time && currentTime <= shift.end_time) {
          return shift;
        }
      }
    }
    return null;
  }

  /**
   * Verifica se si può ordinare in questo momento, considerando un buffer di 1 ora
   * prima/dopo i turni e le chiusure.
   */
  async getOrderingStatus(): Promise<{
    allowed: boolean;
    reason: string;
    currentShift: Shift | null;
  }> {
    const now = new Date();
    const currentTime = now.toTimeString().split(' ')[0];
    const currentDay = now.getDay();
    const adjustedDay = currentDay === 0 ? 7 : currentDay;

    // 1. Controllo chiusure
    const isClosed = await this.isRestaurantClosedToday();
    if (isClosed) {
      return {
        allowed: false,
        reason: 'Ristorante chiuso oggi',
        currentShift: null
      };
    }

    // 2. Filtra i turni attivi per oggi
    const shiftsToday = this.data.filter(shift =>
      shift.is_active && shift.days_of_week.includes(adjustedDay)
    );

    if (shiftsToday.length === 0) {
      return {
        allowed: false,
        reason: 'Nessun turno attivo oggi',
        currentShift: null
      };
    }

    // 3. Controlla se siamo in un turno (con buffer)
    for (const shift of shiftsToday) {
      const startWithBuffer = this.subtractHour(shift.start_time, 1);
      const endWithBuffer = this.addHour(shift.end_time, 1);

      if (this.isTimeInRangeWithOvernight(currentTime, startWithBuffer, endWithBuffer, shift.end_time)) {
        return {
          allowed: true,
          reason: `Turno: ${shift.name}`,
          currentShift: shift
        };
      }
    }

    // 4. Se non siamo nel buffer ma siamo nel turno esatto (es. appena iniziato)
    const exactShift = this.getCurrentShift();
    if (exactShift) {
      return {
        allowed: true,
        reason: `Turno attivo: ${exactShift.name}`,
        currentShift: exactShift
      };
    }

    return {
      allowed: false,
      reason: 'Fuori orario dei turni',
      currentShift: null
    };
  }

  /**
   * Carica le chiusure del ristorante corrente.
   */
  async loadClosures(): Promise<void> {
    try {
      const restaurantId = await this.getCurrentRestaurantId();
      if (!restaurantId) {
        this.closuresSubject.next([]);
        return;
      }

      const { data, error } = await this.run<RestaurantClosures[]>(
        this.supabaseService.getSupabaseClient()
          .from('restaurant_closures')
          .select('*')
          .eq('restaurant_id', restaurantId)
      );

      if (error) throw error;
      this.closuresSubject.next(data || []);
    } catch (error) {
      console.error('Error loading closures:', error);
      this.closuresSubject.next([]);
    }
  }

  /**
   * Verifica se il ristorante è chiuso oggi (basato sulle chiusure caricate).
   */
  async isRestaurantClosedToday(): Promise<boolean> {
    const closures = this.closuresSubject.value;
    if (!closures.length) return false;

    const today = new Date().toISOString().split('T')[0]; // YYYY-MM-DD

    // Adatta questo controllo in base alla struttura effettiva di RestaurantClosures
    return closures.some(closure => {
      // Esempio: se closure ha un campo 'date'
      // return closure.date === today;
      // Se ha intervallo: return today >= closure.start_date && today <= closure.end_date;
      return false; // placeholder, da implementare
    });
  }

  // --- Helper per la gestione degli orari (invariati) ---

  private subtractHour(time: string, hours: number): string {
    const [h, m, s] = time.split(':').map(Number);
    const date = new Date();
    date.setHours(h, m, s);
    date.setHours(date.getHours() - hours);
    return date.toTimeString().split(' ')[0];
  }

  private addHour(time: string, hours: number): string {
    const [h, m, s] = time.split(':').map(Number);
    const date = new Date();
    date.setHours(h, m, s);
    date.setHours(date.getHours() + hours);
    return date.toTimeString().split(' ')[0];
  }

  private isTimeInRangeWithOvernight(
    currentTime: string,
    startTime: string,
    endTimeWithBuffer: string,
    originalEndTime: string
  ): boolean {
    const toMinutes = (time: string) => {
      const [hours, minutes, seconds] = time.split(':').map(Number);
      return hours * 60 + minutes + seconds / 60;
    };

    const current = toMinutes(currentTime);
    const start = toMinutes(startTime);
    const end = toMinutes(endTimeWithBuffer);

    // Caso normale: start <= end
    if (end >= start) {
      return current >= start && current <= end;
    }
    // Oltre mezzanotte: start > end
    return current >= start || current <= end;
  }

  // Metodo di debug (opzionale)
  async debugShiftStatus(): Promise<void> {
    console.log('🔍 ===== DEBUG TURNI =====');
    console.log('Turni caricati:', this.data);
    const status = await this.getOrderingStatus();
    console.log('Stodo ordinamento:', status);
    console.log('===== FINE DEBUG ===== 🔍');
  }

  override ngOnDestroy() {
    super.ngOnDestroy();
    this.authSubscription.unsubscribe();
    this.closuresSubject.complete();
  }
}